import torch
import torch.nn as nn

class PreNormResidualBlock(nn.Module):
    """Pre-norm: LN before sublayer, residual outside."""
    def __init__(self, d_model: int, sublayer: nn.Module):
        super().__init__()
        self.norm     = nn.LayerNorm(d_model)
        self.sublayer = sublayer

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return x + self.sublayer(self.norm(x))   # pre-norm

class PostNormResidualBlock(nn.Module):
    """Post-norm: residual first, then LN."""
    def __init__(self, d_model: int, sublayer: nn.Module):
        super().__init__()
        self.norm     = nn.LayerNorm(d_model)
        self.sublayer = sublayer

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.norm(x + self.sublayer(x))   # post-norm

# WRONG: missing final LN before lm_head
class BrokenGPT(nn.Module):
    def forward(self, tokens):
        x = self.embed(tokens)
        for block in self.blocks:
            x = block(x)
        return self.lm_head(x)   # un-normalized activations → bad logits

# CORRECT: final LN before unembedding
class CorrectGPT(nn.Module):
    def __init__(self):
        super().__init__()
        self.final_ln = nn.LayerNorm(d_model)
    def forward(self, tokens):
        x = self.embed(tokens)
        for block in self.blocks:
            x = block(x)
        x = self.final_ln(x)     # normalize before projection
        return self.lm_head(x)
